"""Frequency Band Scanner — sweep and detect active signals."""
import time
import math
import random

class FrequencyScanner:
    """Sweep frequency bands to detect active emitters."""

    BANDS = {
        'HF': (3e6, 30e6),
        'VHF': (30e6, 300e6),
        'UHF': (300e6, 3e9),
        'SHF': (3e9, 30e9),
        'GPS_L1': (1565.42e6, 1585.42e6),
        'GPS_L2': (1217.6e6, 1237.6e6),
        'WIFI_2G': (2400e6, 2500e6),
        'WIFI_5G': (5725e6, 5875e6),
    }

    def __init__(self, step_hz=100000, dwell_ms=10):
        self.step = step_hz
        self.dwell = dwell_ms / 1000.0
        self.detections = []

    def scan_band(self, band_name, threshold_dbm=-100):
        """Scan a named band and return detections above threshold."""
        if band_name not in self.BANDS:
            return []
        fmin, fmax = self.BANDS[band_name]
        return self.scan_range(fmin, fmax, threshold_dbm)

    def scan_range(self, freq_min, freq_max, threshold_dbm=-100):
        """Scan a frequency range."""
        detections = []
        freq = freq_min
        while freq <= freq_max:
            # Simulated measurement (replace with SDR hardware interface)
            power = -120 + random.gauss(0, 5)  # noise floor
            if power > threshold_dbm:
                det = {'frequency': freq, 'power_dbm': power, 'time': time.time()}
                detections.append(det)
                self.detections.append(det)
            freq += self.step
            time.sleep(self.dwell)
        return detections

    def scan_all_bands(self, threshold_dbm=-100):
        results = {}
        for name in self.BANDS:
            results[name] = self.scan_band(name, threshold_dbm)
        return results

