#!/usr/bin/env python3
"""RF Signal Classifier — identify signal modulation type."""
import math
import collections

class SignalClassifier:
    """Classify RF signals by modulation: CW, pulsed, noise, FM, AM, spread spectrum."""

    def __init__(self):
        self.classifications = []

    def classify(self, samples, sample_rate=1e6):
        """Classify signal from IQ samples (as list of (I, Q) tuples)."""
        if not samples:
            return {'type': 'unknown', 'confidence': 0}

        # Compute amplitude envelope
        amplitudes = [math.sqrt(i*i + q*q) for i, q in samples]
        mean_amp = sum(amplitudes) / len(amplitudes)
        var_amp = sum((a - mean_amp)**2 for a in amplitudes) / len(amplitudes)
        std_amp = math.sqrt(var_amp) if var_amp > 0 else 0

        # Compute instantaneous frequency (phase difference)
        phases = [math.atan2(q, i) for i, q in samples]
        freq_diffs = []
        for k in range(1, len(phases)):
            diff = phases[k] - phases[k-1]
            if diff > math.pi: diff -= 2*math.pi
            if diff < -math.pi: diff += 2*math.pi
            freq_diffs.append(diff)

        freq_var = 0
        if freq_diffs:
            mean_freq = sum(freq_diffs) / len(freq_diffs)
            freq_var = sum((f - mean_freq)**2 for f in freq_diffs) / len(freq_diffs)

        # Classification heuristics
        crest_factor = max(amplitudes) / mean_amp if mean_amp > 0 else 0
        duty_cycle = sum(1 for a in amplitudes if a > mean_amp * 0.5) / len(amplitudes)

        if std_amp / mean_amp < 0.1 and freq_var < 0.01:
            result = {'type': 'CW', 'confidence': 0.9}
        elif crest_factor > 5 and duty_cycle < 0.3:
            result = {'type': 'pulsed', 'confidence': 0.85}
        elif std_amp / mean_amp > 0.8:
            result = {'type': 'noise', 'confidence': 0.8}
        elif freq_var > 0.5 and std_amp / mean_amp < 0.3:
            result = {'type': 'FM', 'confidence': 0.75}
        elif std_amp / mean_amp > 0.3 and freq_var < 0.1:
            result = {'type': 'AM', 'confidence': 0.75}
        elif freq_var > 1.0:
            result = {'type': 'spread_spectrum', 'confidence': 0.7}
        else:
            result = {'type': 'unknown', 'confidence': 0.3}

        result['crest_factor'] = crest_factor
        result['duty_cycle'] = duty_cycle
        result['amplitude_cv'] = std_amp / mean_amp if mean_amp > 0 else 0
        result['freq_variance'] = freq_var
        self.classifications.append(result)
        return result

