#!/usr/bin/env python3
"""Direction of Arrival — multi-antenna AoA calculation."""
import math

class DirectionOfArrival:
    """Compute angle of arrival using phase interferometry."""

    def __init__(self, n_antennas=4, spacing_m=0.15, frequency_hz=1575.42e6):
        self.n_antennas = n_antennas
        self.spacing = spacing_m
        self.c = 299792458
        self.wavelength = self.c / frequency_hz

    def compute_aoa_1d(self, phase_diffs):
        """1D AoA from phase differences between antenna pairs."""
        if not phase_diffs:
            return None
        # Average the sin(theta) estimates
        estimates = []
        for pd in phase_diffs:
            sin_theta = pd * self.wavelength / (2 * math.pi * self.spacing)
            sin_theta = max(-1.0, min(1.0, sin_theta))
            estimates.append(math.degrees(math.asin(sin_theta)))
        return sum(estimates) / len(estimates)

    def compute_aoa_2d(self, phase_diffs_az, phase_diffs_el):
        """2D AoA (azimuth + elevation)."""
        az = self.compute_aoa_1d(phase_diffs_az)
        el = self.compute_aoa_1d(phase_diffs_el)
        return {'azimuth': az, 'elevation': el}

    def triangulate(self, bearing1, pos1, bearing2, pos2):
        """Triangulate emitter position from 2 bearings."""
        b1 = math.radians(bearing1)
        b2 = math.radians(bearing2)
        # Lines: pos1 + t1*(cos(b1), sin(b1)) and pos2 + t2*(cos(b2), sin(b2))
        dx = pos2[0] - pos1[0]
        dy = pos2[1] - pos1[1]
        denom = math.cos(b1) * math.sin(b2) - math.sin(b1) * math.cos(b2)
        if abs(denom) < 1e-10:
            return None  # parallel
        t1 = (dx * math.sin(b2) - dy * math.cos(b2)) / denom
        x = pos1[0] + t1 * math.cos(b1)
        y = pos1[1] + t1 * math.sin(b1)
        return (x, y)

