#!/usr/bin/env python3
"""Signal Fingerprinter — create unique emitter signatures."""
import hashlib
import json
import math

class SignalFingerprinter:
    """Create unique fingerprints for RF emitters based on signal characteristics."""

    def __init__(self):
        self.fingerprints = {}  # fingerprint_id → entry

    def fingerprint(self, frequency, bandwidth, power_dbm, modulation='unknown',
                    pulse_width_us=None, pri_us=None):
        """Generate a fingerprint from signal parameters."""
        features = {
            'freq_mhz': round(frequency / 1e6, 2),
            'bw_khz': round(bandwidth / 1e3, 1),
            'power_dbm': round(power_dbm, 1),
            'modulation': modulation,
        }
        if pulse_width_us is not None:
            features['pw_us'] = round(pulse_width_us, 2)
        if pri_us is not None:
            features['pri_us'] = round(pri_us, 1)

        # Generate deterministic fingerprint hash
        fp_str = json.dumps(features, sort_keys=True)
        fp_id = hashlib.sha256(fp_str.encode()).hexdigest()[:12]

        entry = {'id': fp_id, 'features': features, 'sightings': 1}
        if fp_id in self.fingerprints:
            self.fingerprints[fp_id]['sightings'] += 1
        else:
            self.fingerprints[fp_id] = entry
        return fp_id

    def match(self, frequency, bandwidth, power_dbm, tolerance_mhz=5):
        """Find matching fingerprints within tolerance."""
        matches = []
        freq_mhz = frequency / 1e6
        for fp_id, entry in self.fingerprints.items():
            if abs(entry['features']['freq_mhz'] - freq_mhz) < tolerance_mhz:
                matches.append(entry)
        return sorted(matches, key=lambda x: x['sightings'], reverse=True)

    def export_database(self, path='fingerprints.json'):
        with open(path, 'w') as f:
            json.dump(self.fingerprints, f, indent=2)

