#!/usr/bin/env python3
"""Radar Pulse Descriptor — characterize radar pulses (PRI, PW, RF)."""
import math
import json
import time
import collections

class PulseDescriptor:
    """Analyze and characterize radar pulse trains."""

    def __init__(self):
        self.pulses = []
        self.pulse_trains = []

    def add_pulse(self, toa_s, frequency_hz, amplitude, duration_us):
        """Record a detected pulse."""
        self.pulses.append({
            'toa': toa_s,
            'frequency': frequency_hz,
            'amplitude': amplitude,
            'pw_us': duration_us,
        })

    def analyze_train(self, min_pulses=5):
        """Analyze collected pulses to extract pulse train parameters."""
        if len(self.pulses) < min_pulses:
            return None

        # Sort by time of arrival
        sorted_pulses = sorted(self.pulses, key=lambda p: p['toa'])

        # Compute PRIs (Pulse Repetition Intervals)
        pris = []
        for i in range(1, len(sorted_pulses)):
            pri = sorted_pulses[i]['toa'] - sorted_pulses[i-1]['toa']
            if pri > 0:
                pris.append(pri)

        if not pris:
            return None

        mean_pri = sum(pris) / len(pris)
        pri_var = sum((p - mean_pri)**2 for p in pris) / len(pris)
        pri_jitter = math.sqrt(pri_var) if pri_var > 0 else 0

        # Frequency statistics
        freqs = [p['frequency'] for p in sorted_pulses]
        mean_freq = sum(freqs) / len(freqs)
        freq_spread = max(freqs) - min(freqs)

        # Pulse width stats
        pws = [p['pw_us'] for p in sorted_pulses]
        mean_pw = sum(pws) / len(pws)

        # Classify PRI pattern
        if pri_jitter / mean_pri < 0.02:
            pri_type = 'stable'
        elif pri_jitter / mean_pri < 0.1:
            pri_type = 'jittered'
        else:
            pri_type = 'staggered'

        # Classify frequency pattern
        if freq_spread < 1e6:
            freq_type = 'fixed'
        elif freq_spread < 100e6:
            freq_type = 'agile'
        else:
            freq_type = 'hopping'

        descriptor = {
            'n_pulses': len(sorted_pulses),
            'mean_pri_us': mean_pri * 1e6,
            'prf_hz': 1.0 / mean_pri if mean_pri > 0 else 0,
            'pri_jitter_us': pri_jitter * 1e6,
            'pri_type': pri_type,
            'mean_frequency_ghz': mean_freq / 1e9,
            'freq_spread_mhz': freq_spread / 1e6,
            'freq_type': freq_type,
            'mean_pw_us': mean_pw,
            'duty_cycle': mean_pw * 1e-6 / mean_pri if mean_pri > 0 else 0,
        }
        self.pulse_trains.append(descriptor)
        return descriptor

    def classify_radar(self, descriptor=None):
        """Classify radar type from pulse descriptor."""
        if descriptor is None:
            descriptor = self.analyze_train()
        if descriptor is None:
            return 'unknown'

        prf = descriptor['prf_hz']
        pw = descriptor['mean_pw_us']
        freq = descriptor['mean_frequency_ghz']

        if prf < 500 and pw > 10:
            return 'search_radar'
        elif prf > 5000 and pw < 1:
            return 'fire_control_radar'
        elif 500 <= prf <= 5000:
            return 'tracking_radar'
        elif freq > 20:
            return 'missile_seeker'
        else:
            return 'unknown_radar'
